    91→    fn empty_email_is_rejected() {
    92→        let result = ValidatedEmail::parse("".to_string());
    93→        assert_eq!(result, Err(EmailValidationError::Empty));
    94→    }
    95→
    96→    #[test]
    97→    fn whitespace_only_email_is_rejected() {
    98→        let result = ValidatedEmail::parse("   ".to_string());
    99→        assert_eq!(result, Err(EmailValidationError::Empty));
   100→    }
   101→
